    if (!codec) {
        fprintf(stderr, "libx264 غير متوفر\n");
        return 1;
    }

    AVCodecContext *ctx = avcodec_alloc_context3(codec);
    ctx->width = 1280;
    ctx->height = 720;
    ctx->time_base = (AVRational){1, 25};
    ctx->framerate = (AVRational){25, 1};
    ctx->pix_fmt = AV_PIX_FMT_YUV420P;
n    ctx->gop_size = 12;
    ctx->max_b_frames = 2;
    avcodec_open2(ctx, codec, NULL);

    AVFrame *frame = av_frame_alloc();
n    frame->width = 1280;
    frame->height = 720;
    frame->format = AV_PIX_FMT_YUV420P;
n    av_frame_get_buffer(frame, 0);

    // ملء frame بلون أخضر
    memset(frame->data[0], 0, frame->width * frame->height);
    memset(frame->data[1], 128, frame->width * frame->height / 4);
    memset(frame->data[2], 255, frame->width * frame->height / 4);

    AVPacket *pkt = av_packet_alloc();
    int frame_count = 0;

    for (int i = 0; i < 250; i++) {
        frame->pts = frame_count++;
        int ret = avcodec_send_frame(ctx, frame);
